import '../models/quiz_config.dart';

/// A German noun with gender, English translation, semantic category,
/// difficulty, and whether it's safe for case-declension drilling.
class GermanNoun {
  const GermanNoun({
    required this.noun,
    required this.gender,
    required this.english,
    required this.categories,
    required this.difficulty,
    required this.declensionSafe,
  });

  /// Capitalized German noun, no article (e.g. "Hund").
  final String noun;

  /// 'm' (der), 'f' (die), or 'n' (das).
  final String gender;

  final String english;

  /// Internal category keys, e.g. ['kitchen']. A noun may belong to more
  /// than one category. See [nounCategoryDisplayNames].
  final List<String> categories;

  final NounDifficulty difficulty;

  /// False for weak/n-declension masculine nouns (Junge, Name, Kunde,
  /// Experte, Löwe, Bär, Nachbar, Kollege, Herr, etc.) whose accusative/
  /// dative singular form changes (den/dem Jungen). True otherwise.
  final bool declensionSafe;
}

